import '../lib/event_cursor.dart';
import '../lib/inbox.dart';

void main() {
  final instant = DateTime.utc(2026, 7, 2, 9, 30);
  final accepted = EventInbox().applyBatch([
    LedgerEvent(id: 'second', occurredAt: instant, sequence: 2),
    LedgerEvent(id: 'first', occurredAt: instant, sequence: 1),
  ]);

  final ids = accepted.map((event) => event.id).toList();
  if (ids.length != 2 || ids[0] != 'first' || ids[1] != 'second') {
    throw StateError('equal-time sequence order was not preserved: $ids');
  }
}
